#define ETA 0.3f
#define MOMENTUM 0.3f

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

kernel void bpnn_layerforward_ocl(global float* l1,
                                  global float* l2,
                                  global float* conn,
                                  global float* partial_sum,
                                  local float* local_conn,
                                  local float* local_l1,
                                  int n1,
                                  int n2) {
    int j = get_global_id(1);
    int block_idx = get_global_id(0);

    // j ranges from 1 to n2. l2[0] is not computed here (it's bias or unused).
    if (j >= n2 || j == 0) return;

    int k_start = block_idx * get_local_size(0);
    int k_end = min(k_start + get_local_size(0), n1 + 1);

    float sum = 0.0f;

    for (int k = k_start; k < k_end; k++) {
        // Skip k=0 because the host code adds net->input_weights[0][j] explicitly.
        if (k == 0) continue;

        int conn_idx = k * (n2 + 1) + j;
        float weight = conn[conn_idx];
        float input_val = l1[k];
        sum += weight * input_val;
    }

    partial_sum[block_idx * n2 + (j - 1)] = sum;
}

kernel void bpnn_adjust_weights_ocl(global float* delta,
                                    int ndelta,
                                    global float* ly,
                                    int nly,
                                    global float* w,
                                    global float* oldw) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j > ndelta || j == 0) return;
    if (k > nly) return;

    float delta_val = delta[j];
    float ly_val = ly[k]; // ly[0] is 1.0, set by host or previous layerforward

    int idx = k * (ndelta + 1) + j;
    float old_w = oldw[idx];

    float new_dw = (ETA * delta_val * ly_val) + (MOMENTUM * old_w);

    w[idx] += new_dw;
    oldw[idx] = new_dw;
}
